def validate_tool_context(tool_input):
    required_keys = ['retrieved_docs', 'doc_ids']
    missing = [k for k in required_keys if k not in tool_input]
    if missing:
        print(f'Missing RAG context in tool call: {missing}')
        return False
    if len(tool_input['retrieved_docs']) == 0:
        print('Empty retrieval results in tool call')
        return False
    return True

