@vex_client.verify(test_name="rag-retrieval-quality")
def reliable_rag_agent(messages):
    response = client.messages.create(
        model="claude-3-5-sonnet-20240620",
        max_tokens=1024,
        tools=[
            {
                "type": "retrieval_tool",
                "name": "search_docs",
                "description": "Search documents with relevance scoring"
            }
        ],
        messages=messages
    )

    # Vex auto-detects: relevance < 0.75, empty results, context drift
    if hasattr(response, 'vex_metadata'):
        if response.vex_metadata.get('rag_score') < 0.75:
            # Auto-trigger re-ranking
            response = rerank_and_retry(response)

    return response

